function clmN = fLogClmnFindV01(logTitle,tString,count)%% find column title and return column number% % clmN = fLogclmnFindV01(logTitle,tString)% % clmN: column number for the data you looking for%% logTitle: cell of the column number and log title, from fLogReadV04% tString: title string you are looking for, 'shot number'%%% Function Log Column Find ver.1% % Kei Nakamura% 2013/1/7 ver.4: for new control system%%% load file into a big stringnmbClm = logTitle{end,1};   % number of columnstrLength = numel(tString); % string length for titleclmN = 0;   % in case match not foundfor ii=1:nmbClm    fullS = logTitle{ii,2}; % full string    if numel(fullS)>strLength % if longer        fullS = fullS(1:strLength); % make it partial string    end    if strcmp(tString,fullS)        clmN = ii;        break % if find mathced, break the loop    end   end%% previous version% clmN = 0;   % in case match not found% for ii=1:nmbClm%     if strLength==numel(logTitle{ii,2}) % first find the title with the same length%         logicS = tString==logTitle{ii,2};   % then compare%         if sum(logicS)==strLength % if the same, sum(logic) = length%             clmN = ii;%             break % if find mathced, break the loop%         end       %     end    % end%%if nargin==2        if clmN==0        error('match not found')    endelseif clmN==0    disp('no match but continue')    % no error stop, continueend
